// // This module implements a 2:1 multiplexer with an enable signal.
// It outputs data_in_1 when enable is low and data_in_0 when enable is high.
module mux_2to1_enable(
    input data_in_0,
    input data_in_1,
    input enable,
    output reg data_out
);

always @(*) begin
    if(enable == 1'b0) begin
        data_out = data_in_0;
    end
    else begin
        data_out = data_in_1;
    end
end

endmodule
